void Dtool_libp3distort_RegisterTypes() {
  TypeRegistry *registry = TypeRegistry::ptr();
  nassertv(registry != nullptr);
  {
    CylindricalLens::init_type();
    TypeHandle handle = CylindricalLens::get_class_type();
    Dtool_CylindricalLens._type = handle;
    registry->record_python_type(handle, &Dtool_CylindricalLens._PyType, Dtool_Wrap_CylindricalLens);
  }
  {
    FisheyeLens::init_type();
    TypeHandle handle = FisheyeLens::get_class_type();
    Dtool_FisheyeLens._type = handle;
    registry->record_python_type(handle, &Dtool_FisheyeLens._PyType, Dtool_Wrap_FisheyeLens);
  }
  {
    ProjectionScreen::init_type();
    TypeHandle handle = ProjectionScreen::get_class_type();
    Dtool_ProjectionScreen._type = handle;
    registry->record_python_type(handle, &Dtool_ProjectionScreen._PyType, Dtool_Wrap_ProjectionScreen);
  }
  {
    OSphereLens::init_type();
    TypeHandle handle = OSphereLens::get_class_type();
    Dtool_OSphereLens._type = handle;
    registry->record_python_type(handle, &Dtool_OSphereLens._PyType, Dtool_Wrap_OSphereLens);
  }
  {
    PSphereLens::init_type();
    TypeHandle handle = PSphereLens::get_class_type();
    Dtool_PSphereLens._type = handle;
    registry->record_python_type(handle, &Dtool_PSphereLens._PyType, Dtool_Wrap_PSphereLens);
  }
}

void Dtool_libp3distort_BuildInstants(PyObject *module) {
  (void) module;
  // CylindricalLens
  Dtool_PyModuleClassInit_CylindricalLens(module);
  PyModule_AddObject(module, "CylindricalLens", (PyObject *)&Dtool_CylindricalLens);
  // FisheyeLens
  Dtool_PyModuleClassInit_FisheyeLens(module);
  PyModule_AddObject(module, "FisheyeLens", (PyObject *)&Dtool_FisheyeLens);
  // ProjectionScreen
  Dtool_PyModuleClassInit_ProjectionScreen(module);
  PyModule_AddObject(module, "ProjectionScreen", (PyObject *)&Dtool_ProjectionScreen);
  // NonlinearImager
  Dtool_PyModuleClassInit_NonlinearImager(module);
  PyModule_AddObject(module, "NonlinearImager", (PyObject *)&Dtool_NonlinearImager);
  // OSphereLens
  Dtool_PyModuleClassInit_OSphereLens(module);
  PyModule_AddObject(module, "OSphereLens", (PyObject *)&Dtool_OSphereLens);
  // PSphereLens
  Dtool_PyModuleClassInit_PSphereLens(module);
  PyModule_AddObject(module, "PSphereLens", (PyObject *)&Dtool_PSphereLens);
}

